/**
 * Passo 1 — Normaliza a entrada e calcula hash determinístico.
 *
 * Adota estilo OPIN: espera envelope { data: { ... } }. Se o cliente mandar
 * sem envelope (modo tolerante para testes rápidos), aceita também.
 *
 * O header `x-idempotency-key`, se presente, entra no hash e permite ao
 * cliente controlar quando quer uma nova cotação.
 */

const incoming = $input.first().json;
const body = incoming.body ?? incoming;
const headers = incoming.headers ?? {};
const payload = body.data ?? body;

function onlyDigits(s) {
  return String(s ?? '').replace(/\D/g, '');
}
function normalizeDate(s) {
  if (!s) return null;
  return String(s).slice(0, 10);
}
function toNum(v) {
  const n = Number(v);
  return Number.isFinite(n) ? n : 0;
}

// Beneficiários: obrigatório ao menos 1
const beneficiarios = Array.isArray(payload.beneficiarios) ? payload.beneficiarios : [];
if (beneficiarios.length === 0) {
  throw new Error('VALIDATION: payload.beneficiarios é obrigatório e deve conter ao menos 1 item.');
}

// Validar percentuais somam 100 (tolerância 0.01)
const totalPct = beneficiarios.reduce((s, b) => s + toNum(b.percentual), 0);
if (Math.abs(totalPct - 100) > 0.01) {
  throw new Error(`VALIDATION: percentuais dos beneficiários devem somar 100. Recebido: ${totalPct}`);
}

const sexoNormalizado = String(payload.segurado?.sexo ?? 'm').toLowerCase().charAt(0);
if (!['m', 'f'].includes(sexoNormalizado)) {
  throw new Error('VALIDATION: sexo do segurado deve ser "m" ou "f".');
}

const capitalMorte = toNum(payload.cobertura?.capitalMorte);
if (capitalMorte < 10000) {
  throw new Error('VALIDATION: cobertura.capitalMorte é obrigatório e deve ser >= R$ 10.000.');
}

const normalized = {
  contratante: {
    cep: onlyDigits(payload.contratante?.cep)
  },
  segurado: {
    cpf: onlyDigits(payload.segurado?.cpf),
    dataNascimento: normalizeDate(payload.segurado?.dataNascimento),
    sexo: sexoNormalizado,
    fumante: Boolean(payload.segurado?.fumante ?? false),
    profissao: String(payload.segurado?.profissao ?? 'outros').toLowerCase()
  },
  beneficiarios: beneficiarios
    .map(b => ({
      nome: String(b.nome ?? '').trim(),
      parentesco: String(b.parentesco ?? 'outro').toLowerCase(),
      percentual: Math.round(toNum(b.percentual) * 100) / 100
    }))
    .sort((a, b) =>
      a.parentesco.localeCompare(b.parentesco) ||
      a.nome.localeCompare(b.nome)
    ),
  cobertura: {
    capitalMorte,
    capitalInvalidezAcidente: toNum(payload.cobertura?.capitalInvalidezAcidente),
    capitalInvalidezDoenca: toNum(payload.cobertura?.capitalInvalidezDoenca),
    capitalDoencasGraves: toNum(payload.cobertura?.capitalDoencasGraves),
    auxilioFuneral: toNum(payload.cobertura?.auxilioFuneral),
    diariaIncapacidade: toNum(payload.cobertura?.diariaIncapacidade),
    prazo: String(payload.cobertura?.prazo ?? 'anualRenovavel')
  },
  idempotencyKey: headers['x-idempotency-key'] ?? null
};

// cyrb128 — hash determinístico 128 bits (4 uint32).
function cyrb128(str) {
  let h1 = 1779033703, h2 = 3144134277, h3 = 1013904242, h4 = 2773480762;
  for (let i = 0, k; i < str.length; i++) {
    k = str.charCodeAt(i);
    h1 = h2 ^ Math.imul(h1 ^ k, 597399067);
    h2 = h3 ^ Math.imul(h2 ^ k, 2869860233);
    h3 = h4 ^ Math.imul(h3 ^ k, 951274213);
    h4 = h1 ^ Math.imul(h4 ^ k, 2716044179);
  }
  h1 = Math.imul(h3 ^ (h1 >>> 18), 597399067);
  h2 = Math.imul(h4 ^ (h2 >>> 22), 2869860233);
  h3 = Math.imul(h1 ^ (h3 >>> 17), 951274213);
  h4 = Math.imul(h2 ^ (h4 >>> 19), 2716044179);
  h1 ^= (h2 ^ h3 ^ h4); h2 ^= h1; h3 ^= h1; h4 ^= h1;
  return [h1 >>> 0, h2 >>> 0, h3 >>> 0, h4 >>> 0];
}

const hashParts = cyrb128(JSON.stringify(normalized));
const hashHex = hashParts.map(n => n.toString(16).padStart(8, '0')).join('');

const consentId = [
  'urn:opin-mock:life:consent:',
  hashHex.slice(0, 8), '-',
  hashHex.slice(8, 12), '-',
  hashHex.slice(12, 16), '-',
  hashHex.slice(16, 20), '-',
  hashHex.slice(20, 32)
].join('');

return [{
  json: { normalized, hashHex, seed: hashParts[0], consentId }
}];

/**
 * Passo 2 — Gera cotação de VIDA determinística e monta envelope OPIN-style.
 *
 * Preço sensível a idade, sexo, fumo e coberturas. PRNG seedado no hash:
 * mesmos inputs → mesmos preços. Planos ordenados por prêmio mensal.
 */

const { normalized, hashHex, seed, consentId } = $input.first().json;

let s = seed;
const rand = () => {
  s = (s + 0x6D2B79F5) | 0;
  let t = s;
  t = Math.imul(t ^ (t >>> 15), t | 1);
  t ^= t + Math.imul(t ^ (t >>> 7), t | 61);
  return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
};
const randRange = (min, max) => min + rand() * (max - min);

function idadeAnos(dataNascimento) {
  if (!dataNascimento) return 35;
  const nasc = DateTime.fromISO(dataNascimento);
  if (!nasc.isValid) return 35;
  return Math.max(0, Math.floor(DateTime.now().diff(nasc, 'years').years));
}

// Faixas etárias vida: taxa anual por R$ 1.000 de capital morte
const faixasEtarias = [
  { min: 0,  max: 22,  taxa: 1.20 },
  { min: 23, max: 27,  taxa: 1.40 },
  { min: 28, max: 32,  taxa: 1.65 },
  { min: 33, max: 37,  taxa: 1.95 },
  { min: 38, max: 42,  taxa: 2.35 },
  { min: 43, max: 47,  taxa: 3.00 },
  { min: 48, max: 52,  taxa: 4.20 },
  { min: 53, max: 57,  taxa: 6.00 },
  { min: 58, max: 62,  taxa: 8.50 },
  { min: 63, max: 150, taxa: 12.00 }
];
function taxaPorIdade(idade) {
  const f = faixasEtarias.find(f => idade >= f.min && idade <= f.max);
  return f ? f.taxa : 12.0;
}

const idade = idadeAnos(normalized.segurado.dataNascimento);
const sexo = normalized.segurado.sexo;
const fumante = normalized.segurado.fumante;

const taxaBase = taxaPorIdade(idade);
const multSexo    = sexo === 'f' ? 0.72 : 1.00;
const multFumante = fumante ? 1.85 : 1.00;

// Profissões de risco (sem lista fechada: só alguns exemplos)
const profRisco = ['motoboy', 'motofrete', 'bombeiro', 'policial', 'seguranca armada', 'eletricista industrial'];
const multRisco = profRisco.some(p => normalized.segurado.profissao.includes(p)) ? 1.35 : 1.0;

const cob = normalized.cobertura;
const K = cob.capitalMorte / 1000;
const Kia = cob.capitalInvalidezAcidente / 1000;
const Kid = cob.capitalInvalidezDoenca / 1000;
const Kdg = cob.capitalDoencasGraves / 1000;
const Kaf = cob.auxilioFuneral / 1000;
const Kdi = cob.diariaIncapacidade;

// Taxas adicionais (por R$ 1.000 de capital, anual)
const taxaIA = 0.55;   // invalidez por acidente
const taxaID = 1.80;   // invalidez por doença
const taxaDG = 3.00;   // doenças graves
const taxaAF = 18.00;  // auxílio funeral (capital baixo)
const taxaDI = 14.00;  // diária incapacidade (por R$ de diária)

// Prêmio anual base (considerando todos os fatores)
function premioAnual(multMarca) {
  const base = K * taxaBase * multSexo * multFumante * multRisco;
  const adic = (Kia * taxaIA) + (Kid * taxaID) + (Kdg * taxaDG) + (Kaf * taxaAF) + (Kdi * taxaDI);
  return (base + adic) * multMarca;
}

const operadoras = [
  {
    codigo: 'BRD',
    nome: 'Bradesco Seguros',
    registroSusep: '0153-1',
    produto: 'Viver Bem Individual',
    multMarca: 1.00,
    carenciaMorteNatural: 24
  },
  {
    codigo: 'ICA',
    nome: 'Icatu Seguros',
    registroSusep: '0168-0',
    produto: 'Icatu Vida Master',
    multMarca: 0.92,
    carenciaMorteNatural: 12
  },
  {
    codigo: 'MAG',
    nome: 'MAG Seguros',
    registroSusep: '0153-9',
    produto: 'MAG Premier Vida',
    multMarca: 1.08,
    carenciaMorteNatural: 24
  }
];

const planos = operadoras
  .map(op => {
    const ruido = 1 + randRange(-0.03, 0.03);
    const anual = Math.round(premioAnual(op.multMarca) * ruido * 100) / 100;
    const mensal = Math.round(anual / 12 * 100) / 100;

    const coberturasList = [
      { tipo: 'morte',              capital: cob.capitalMorte }
    ];
    if (cob.capitalInvalidezAcidente > 0) coberturasList.push({ tipo: 'invalidez_permanente_acidente', capital: cob.capitalInvalidezAcidente });
    if (cob.capitalInvalidezDoenca  > 0) coberturasList.push({ tipo: 'invalidez_permanente_doenca',   capital: cob.capitalInvalidezDoenca });
    if (cob.capitalDoencasGraves    > 0) coberturasList.push({ tipo: 'doencas_graves',                capital: cob.capitalDoencasGraves });
    if (cob.auxilioFuneral          > 0) coberturasList.push({ tipo: 'auxilio_funeral',               capital: cob.auxilioFuneral });
    if (cob.diariaIncapacidade      > 0) coberturasList.push({ tipo: 'diaria_incapacidade_temporaria', valorDiario: cob.diariaIncapacidade });

    return {
      planId: `${op.codigo}-${hashHex.slice(0, 6)}`,
      operadora: {
        codigo: op.codigo,
        nome: op.nome,
        registroSusep: op.registroSusep
      },
      produto: {
        nome: `${op.nome} ${op.produto}`,
        prazo: cob.prazo
      },
      premio: {
        mensal,
        anual,
        iof: 0.0038 * anual,
        moeda: 'BRL'
      },
      coberturas: coberturasList,
      carencias: {
        morteNatural: op.carenciaMorteNatural === 0 ? 'sem carência' : `${op.carenciaMorteNatural} meses para DPPs`,
        morteAcidental: 'sem carência',
        invalidezAcidente: 'sem carência',
        invalidezDoenca: '24 meses para DPPs',
        doencasGraves: '90 dias',
        diariaIncapacidade: '60 dias'
      },
      vigencia: {
        tipo: cob.prazo,
        renovacao: cob.prazo === 'anualRenovavel' ? 'automática com recálculo anual' : 'não renovável'
      },
      exclusoesImportantes: [
        'Doenças preexistentes não declaradas',
        'Suicídio nos primeiros 24 meses',
        'Atos dolosos do segurado'
      ]
    };
  })
  .sort((a, b) => a.premio.mensal - b.premio.mensal);

function formatCpf(digits) {
  if (!digits || digits.length !== 11) return null;
  return digits.replace(/(\d{3})(\d{3})(\d{3})(\d{2})/, '$1.$2.$3-$4');
}

const now = DateTime.now();

return [{
  json: {
    data: {
      consentId,
      quoteStatus: 'ACKNOWLEDGED',
      requestDateTime: now.toISO(),
      validadeDias: 30,
      contratante: normalized.contratante,
      segurado: {
        cpf: formatCpf(normalized.segurado.cpf),
        dataNascimento: normalized.segurado.dataNascimento,
        idade,
        sexo: normalized.segurado.sexo,
        fumante: normalized.segurado.fumante,
        profissao: normalized.segurado.profissao
      },
      beneficiarios: normalized.beneficiarios,
      cobertura: normalized.cobertura,
      planos
    },
    meta: {
      totalPlanos: planos.length,
      apiVersion: 'opin-style-life-v1',
      deterministicHash: hashHex.slice(0, 16),
      requestDateTime: now.toISO(),
      disclaimer: 'Resposta simulada. Vida é regulada pela SUSEP; as faixas, taxas e preços aqui são didáticos. Em produção, usar API da seguradora parceira.'
    }
  }
}];

/**
 * Passo 1 — Valida consentId recalculando o hash do originalQuoteRequest.
 *
 * Mock stateless: cliente precisa reenviar `originalQuoteRequest`
