  },
  segurado: {
    cpf: onlyDigits(originalQuoteRequest.segurado?.cpf),
    dataNascimento: normalizeDate(originalQuoteRequest.segurado?.dataNascimento),
    sexo: sexoNormalizado,
    fumante: Boolean(originalQuoteRequest.segurado?.fumante ?? false),
    profissao: String(originalQuoteRequest.segurado?.profissao ?? 'outros').toLowerCase()
  },
  beneficiarios: beneficiarios
    .map(b => ({
      nome: String(b.nome ?? '').trim(),
      parentesco: String(b.parentesco ?? 'outro').toLowerCase(),
      percentual: Math.round(toNum(b.percentual) * 100) / 100
    }))
    .sort((a, b) =>
      a.parentesco.localeCompare(b.parentesco) ||
      a.nome.localeCompare(b.nome)
    ),
  cobertura: {
    capitalMorte: toNum(originalQuoteRequest.cobertura?.capitalMorte),
    capitalInvalidezAcidente: toNum(originalQuoteRequest.cobertura?.capitalInvalidezAcidente),
    capitalInvalidezDoenca: toNum(originalQuoteRequest.cobertura?.capitalInvalidezDoenca),
    capitalDoencasGraves: toNum(originalQuoteRequest.cobertura?.capitalDoencasGraves),
    auxilioFuneral: toNum(originalQuoteRequest.cobertura?.auxilioFuneral),
    diariaIncapacidade: toNum(originalQuoteRequest.cobertura?.diariaIncapacidade),
    prazo: String(originalQuoteRequest.cobertura?.prazo ?? 'anualRenovavel')
  },
  idempotencyKey: headers['x-idempotency-key'] ?? null
};

function cyrb128(str) {
  let h1 = 1779033703, h2 = 3144134277, h3 = 1013904242, h4 = 2773480762;
  for (let i = 0, k; i < str.length; i++) {
    k = str.charCodeAt(i);
    h1 = h2 ^ Math.imul(h1 ^ k, 597399067);
    h2 = h3 ^ Math.imul(h2 ^ k, 2869860233);
    h3 = h4 ^ Math.imul(h3 ^ k, 951274213);
    h4 = h1 ^ Math.imul(h4 ^ k, 2716044179);
  }
  h1 = Math.imul(h3 ^ (h1 >>> 18), 597399067);
  h2 = Math.imul(h4 ^ (h2 >>> 22), 2869860233);
  h3 = Math.imul(h1 ^ (h3 >>> 17), 951274213);
  h4 = Math.imul(h2 ^ (h4 >>> 19), 2716044179);
  h1 ^= (h2 ^ h3 ^ h4); h2 ^= h1; h3 ^= h1; h4 ^= h1;
  return [h1 >>> 0, h2 >>> 0, h3 >>> 0, h4 >>> 0];
}

const hashParts = cyrb128(JSON.stringify(normalized));
const hashHex = hashParts.map(n => n.toString(16).padStart(8, '0')).join('');
const expectedConsentId = [
  'urn:opin-mock:life:consent:',
  hashHex.slice(0, 8), '-',
  hashHex.slice(8, 12), '-',
  hashHex.slice(12, 16), '-',
  hashHex.slice(16, 20), '-',
  hashHex.slice(20, 32)
].join('');

const consentMatches = expectedConsentId === consentIdFromPath;

return [{
  json: {
    consentMatches,
    consentIdFromPath,
    expectedConsentId,
    normalized,
    hashHex,
    seed: hashParts[0],
    selectedPlan,
    paymentConfirmation,
    __error: null
  }
}];

/**
 * Passo 2 (sucesso) — Emite apólice de VIDA determinística.
 *
 * Usa o mesmo PRNG do fluxo de cotação para que o prêmio emitido bata com
 * o mostrado na cotação. Deriva `policyNumber` do hash + código da operadora.
 * Vigência padrão: 12 meses anuais renováveis.
 */

const { normalized, hashHex, seed, selectedPlan, paymentConfirmation, consentIdFromPath } = $input.first().json;

let s = seed;
const rand = () => {
  s = (s + 0x6D2B79F5) | 0;
  let t = s;
  t = Math.imul(t ^ (t >>> 15), t | 1);
  t ^= t + Math.imul(t ^ (t >>> 7), t | 61);
  return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
};
const randRange = (min, max) => min + rand() * (max - min);

function idadeAnos(dataNascimento) {
  if (!dataNascimento) return 35;
  const nasc = DateTime.fromISO(dataNascimento);
  if (!nasc.isValid) return 35;
  return Math.max(0, Math.floor(DateTime.now().diff(nasc, 'years').years));
}

const faixasEtarias = [
  { min: 0,  max: 22,  taxa: 1.20 },
  { min: 23, max: 27,  taxa: 1.40 },
  { min: 28, max: 32,  taxa: 1.65 },
  { min: 33, max: 37,  taxa: 1.95 },
  { min: 38, max: 42,  taxa: 2.35 },
  { min: 43, max: 47,  taxa: 3.00 },
  { min: 48, max: 52,  taxa: 4.20 },
  { min: 53, max: 57,  taxa: 6.00 },
  { min: 58, max: 62,  taxa: 8.50 },
  { min: 63, max: 150, taxa: 12.00 }
];
function taxaPorIdade(idade) {
  const f = faixasEtarias.find(f => idade >= f.min && idade <= f.max);
  return f ? f.taxa : 12.0;
}

const idade = idadeAnos(normalized.segurado.dataNascimento);
const sexo = normalized.segurado.sexo;
const fumante = normalized.segurado.fumante;

const taxaBase = taxaPorIdade(idade);
const multSexo = sexo === 'f' ? 0.72 : 1.00;
const multFumante = fumante ? 1.85 : 1.00;
const profRisco = ['motoboy', 'motofrete', 'bombeiro', 'policial', 'seguranca armada', 'eletricista industrial'];
const multRisco = profRisco.some(p => normalized.segurado.profissao.includes(p)) ? 1.35 : 1.0;

const cob = normalized.cobertura;
const K = cob.capitalMorte / 1000;
const Kia = cob.capitalInvalidezAcidente / 1000;
const Kid = cob.capitalInvalidezDoenca / 1000;
const Kdg = cob.capitalDoencasGraves / 1000;
const Kaf = cob.auxilioFuneral / 1000;
const Kdi = cob.diariaIncapacidade;

const taxaIA = 0.55, taxaID = 1.80, taxaDG = 3.00, taxaAF = 18.00, taxaDI = 14.00;

const operadoras = [
  { codigo: 'BRD', nome: 'Bradesco Seguros', registroSusep: '0153-1', produto: 'Viver Bem Individual', multMarca: 1.00, carenciaMorteNatural: 24 },
  { codigo: 'ICA', nome: 'Icatu Seguros',    registroSusep: '0168-0', produto: 'Icatu Vida Master',    multMarca: 0.92, carenciaMorteNatural: 12 },
  { codigo: 'MAG', nome: 'MAG Seguros',      registroSusep: '0153-9', produto: 'MAG Premier Vida',     multMarca: 1.08, carenciaMorteNatural: 24 }
];

function premioAnual(multMarca) {
  const base = K * taxaBase * multSexo * multFumante * multRisco;
  const adic = (Kia * taxaIA) + (Kid * taxaID) + (Kdg * taxaDG) + (Kaf * taxaAF) + (Kdi * taxaDI);
  return (base + adic) * multMarca;
}

// Recompute planos in the SAME order the quote flow did so the PRNG aligns
const planosRecomputados = operadoras.map(op => {
  const ruido = 1 + randRange(-0.03, 0.03);
  const anual = Math.round(premioAnual(op.multMarca) * ruido * 100) / 100;
  const mensal = Math.round(anual / 12 * 100) / 100;
  return {
    planId: `${op.codigo}-${hashHex.slice(0, 6)}`,
    operadora: op,
    premio: { mensal, anual, iof: 0.0038 * anual, moeda: 'BRL' }
  };
});

// Match the selected plan by planId or operadora.codigo
const planoEscolhido = planosRecomputados.find(p =>
  (selectedPlan.planId && p.planId === selectedPlan.planId) ||
  (selectedPlan.operadora?.codigo && p.operadora.codigo === selectedPlan.operadora.codigo)
);

if (!planoEscolhido) {
  throw new Error(`Plano selecionado não encontrado na cotação original: ${JSON.stringify(selectedPlan)}`);
}

// Gera policyNumber determinístico
const policyNumber = `LV-${planoEscolhido.operadora.codigo}-${hashHex.slice(0, 8).toUpperCase()}`;
const policyId = `urn:opin-mock:life:policy:${hashHex.slice(0, 8)}-${hashHex.slice(8, 12)}-${hashHex.slice(12, 16)}-${hashHex.slice(16, 20)}-${hashHex.slice(20, 32)}`;

const now = DateTime.now();
const startDate = now;
const endDate = now.plus({ years: 1 });

// Monta lista de coberturas para a apólice emitida
const coberturasEmitidas = [
  { tipo: 'morte', capital: cob.capitalMorte }
];
if (cob.capitalInvalidezAcidente > 0) coberturasEmitidas.push({ tipo: 'invalidez_permanente_acidente', capital: cob.capitalInvalidezAcidente });
if (cob.capitalInvalidezDoenca  > 0) coberturasEmitidas.push({ tipo: 'invalidez_permanente_doenca',   capital: cob.capitalInvalidezDoenca });
if (cob.capitalDoencasGraves    > 0) coberturasEmitidas.push({ tipo: 'doencas_graves',                capital: cob.capitalDoencasGraves });
if (cob.auxilioFuneral          > 0) coberturasEmitidas.push({ tipo: 'auxilio_funeral',               capital: cob.auxilioFuneral });
