/**
 * Passo 1 (Auto) — Normaliza entrada e calcula hash determinístico.
 *
 * Estilo OPIN: espera envelope { data: { ... } }. Aceita sem envelope (tolerante).
 * Header x-idempotency-key entra no hash se presente.
 */

const incoming = $input.first().json;
const body = incoming.body ?? incoming;
const headers = incoming.headers ?? {};
const payload = body.data ?? body;

function onlyDigits(s) {
  return String(s ?? '').replace(/\D/g, '');
}
function normalizeDate(s) {
  if (!s) return null;
  return String(s).slice(0, 10);
}
function toNum(v) {
  const n = Number(v);
  return Number.isFinite(n) ? n : 0;
}

const veiculo = payload.veiculo ?? {};
const condutor = payload.condutor ?? {};
const localizacao = payload.localizacao ?? {};
const cobertura = payload.cobertura ?? {};

if (!veiculo.placa && !veiculo.chassi) {
  throw new Error('VALIDATION: veiculo.placa (ou chassi) é obrigatório.');
}
if (!condutor.cpf) {
  throw new Error('VALIDATION: condutor.cpf é obrigatório.');
}
if (!localizacao.cep) {
  throw new Error('VALIDATION: localizacao.cep é obrigatório.');
}

const anoModelo = toNum(veiculo.anoModelo);
if (anoModelo < 1980 || anoModelo > 2100) {
  throw new Error('VALIDATION: veiculo.anoModelo inválido.');
}

const sexoNorm = String(condutor.sexo ?? 'm').toLowerCase().charAt(0);
if (!['m', 'f'].includes(sexoNorm)) {
  throw new Error('VALIDATION: condutor.sexo deve ser "m" ou "f".');
}

const tipoCoberturaNorm = String(cobertura.tipo ?? 'compreensiva').toLowerCase();
if (!['compreensiva', 'rcf', 'app', 'basica'].includes(tipoCoberturaNorm)) {
  throw new Error('VALIDATION: cobertura.tipo deve ser "compreensiva", "rcf", "app" ou "basica".');
}

const normalized = {
  veiculo: {
    placa: String(veiculo.placa ?? '').toUpperCase().replace(/[^A-Z0-9]/g, ''),
    chassi: String(veiculo.chassi ?? '').toUpperCase().replace(/[^A-Z0-9]/g, ''),
    marca: String(veiculo.marca ?? '').toLowerCase(),
    modelo: String(veiculo.modelo ?? '').toLowerCase(),
    anoModelo,
    combustivel: String(veiculo.combustivel ?? 'flex').toLowerCase(),
    categoria: String(veiculo.categoria ?? 'passeio').toLowerCase(),
  },
  condutor: {
    cpf: onlyDigits(condutor.cpf),
    dataNascimento: normalizeDate(condutor.dataNascimento),
    sexo: sexoNorm,
    cnhDesde: normalizeDate(condutor.cnhDesde),
    estadoCivil: String(condutor.estadoCivil ?? 'solteiro').toLowerCase(),
    usoPrincipal: String(condutor.usoPrincipal ?? 'particular').toLowerCase(),
  },
  localizacao: {
    cep: onlyDigits(localizacao.cep),
    cidade: String(localizacao.cidade ?? '').toLowerCase(),
    usoComercial: Boolean(localizacao.usoComercial ?? false),
    garagem: Boolean(localizacao.garagem ?? true),
  },
  cobertura: {
    tipo: tipoCoberturaNorm,
    franquiaPerfil: String(cobertura.franquiaPerfil ?? 'normal').toLowerCase(),
    appCapital: toNum(cobertura.appCapital),
    rcfMateriais: toNum(cobertura.rcfMateriais),
    rcfCorporais: toNum(cobertura.rcfCorporais),
  },
  idempotencyKey: headers['x-idempotency-key'] ?? null
};

function cyrb128(str) {
  let h1 = 1779033703, h2 = 3144134277, h3 = 1013904242, h4 = 2773480762;
  for (let i = 0, k; i < str.length; i++) {
    k = str.charCodeAt(i);
    h1 = h2 ^ Math.imul(h1 ^ k, 597399067);
    h2 = h3 ^ Math.imul(h2 ^ k, 2869860233);
    h3 = h4 ^ Math.imul(h3 ^ k, 951274213);
    h4 = h1 ^ Math.imul(h4 ^ k, 2716044179);
  }
  h1 = Math.imul(h3 ^ (h1 >>> 18), 597399067);
  h2 = Math.imul(h4 ^ (h2 >>> 22), 2869860233);
  h3 = Math.imul(h1 ^ (h3 >>> 17), 951274213);
  h4 = Math.imul(h2 ^ (h4 >>> 19), 2716044179);
  h1 ^= (h2 ^ h3 ^ h4); h2 ^= h1; h3 ^= h1; h4 ^= h1;
  return [h1 >>> 0, h2 >>> 0, h3 >>> 0, h4 >>> 0];
}

const hashParts = cyrb128(JSON.stringify(normalized));
const hashHex = hashParts.map(n => n.toString(16).padStart(8, '0')).join('');

const consentId = [
  'urn:opin-mock:auto:consent:',
  hashHex.slice(0, 8), '-',
  hashHex.slice(8, 12), '-',
  hashHex.slice(12, 16), '-',
  hashHex.slice(16, 20), '-',
  hashHex.slice(20, 32)
].join('');

return [{
  json: { normalized, hashHex, seed: hashParts[0], consentId }
}];

/**
 * Passo 2 (Auto) — Gera cotação de AUTO determinística, envelope OPIN-style.
 *
 * Preço sensível a: idade do condutor, anos de CNH, sexo, ano do veículo,
 * tipo de cobertura, franquia, CEP (risco por prefixo), uso comercial e garagem.
 * PRNG seedado no hash → mesmos inputs retornam mesmos preços.
 */

const { normalized, hashHex, seed, consentId } = $input.first().json;

let s = seed;
const rand = () => {
  s = (s + 0x6D2B79F5) | 0;
  let t = s;
  t = Math.imul(t ^ (t >>> 15), t | 1);
  t ^= t + Math.imul(t ^ (t >>> 7), t | 61);
  return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
};
const randRange = (min, max) => min + rand() * (max - min);

function idadeAnos(dataNascimento) {
  if (!dataNascimento) return 35;
  const nasc = DateTime.fromISO(dataNascimento);
  if (!nasc.isValid) return 35;
  return Math.max(0, Math.floor(DateTime.now().diff(nasc, 'years').years));
}

function anosHabilitado(cnhDesde) {
  if (!cnhDesde) return 5;
  const d = DateTime.fromISO(cnhDesde);
  if (!d.isValid) return 5;
  return Math.max(0, Math.floor(DateTime.now().diff(d, 'years').years));
}

// FIPE simulado por ano: valor base do veículo
function valorFipeSimulado(anoModelo, categoria) {
  const anosUso = Math.max(0, DateTime.now().year - anoModelo);
  const depreciacao = Math.max(0.25, 1 - anosUso * 0.09);
  const baseCategorias = {
    'passeio': 80000,
    'hatch': 65000,
    'sedan': 95000,
    'suv': 140000,
    'pickup': 180000,
    'utilitario': 110000,
  };
  const base = baseCategorias[categoria] ?? 85000;
  return Math.round(base * depreciacao);
}

// Risco por CEP (prefixo 2 dígitos aproxima região; mock grosseiro)
function riscoCep(cep) {
  const p = Number(String(cep).slice(0, 2));
  if (!Number.isFinite(p)) return 1.0;
  // Capitais com histórico de sinistralidade mais alta (SP/RJ/NE):
  if ([1, 2, 3, 4, 5, 20, 21, 22, 23, 24, 50, 51, 52, 53, 54, 55, 57, 58].includes(p)) return 1.20;
  // Demais capitais (mediano)
  if ([13, 40, 41, 60, 69, 70, 80, 90].includes(p)) return 1.05;
  return 0.95;
}

const idade = idadeAnos(normalized.condutor.dataNascimento);
const anosCnh = anosHabilitado(normalized.condutor.cnhDesde);
const sexo = normalized.condutor.sexo;
const anoModelo = normalized.veiculo.anoModelo;
const fipe = valorFipeSimulado(anoModelo, normalized.veiculo.categoria);

// Taxa base (anual, por % do valor FIPE)
function taxaPorIdade(i) {
  if (i < 25) return 0.080;
  if (i < 30) return 0.055;
  if (i < 40) return 0.038;
  if (i < 55) return 0.030;
  if (i < 65) return 0.034;
  return 0.045;
}

const taxaBase = taxaPorIdade(idade);
const multSexo = sexo === 'f' ? 0.90 : 1.00;
const multExperiencia = anosCnh < 2 ? 1.40 : anosCnh < 5 ? 1.15 : anosCnh < 15 ? 1.00 : 0.93;
const multUsoComercial = normalized.localizacao.usoComercial ? 1.25 : 1.00;
const multGaragem = normalized.localizacao.garagem ? 0.93 : 1.08;
const multCep = riscoCep(normalized.localizacao.cep);

// Cobertura
const multCobertura = {
  'compreensiva': 1.00,
  'rcf': 0.45,
  'app': 0.20,
  'basica': 0.30,
}[normalized.cobertura.tipo] ?? 1.00;

// Franquia perfil (franquia reduzida = prêmio mais alto)
const multFranquia = {
  'reduzida': 1.18,
  'normal': 1.00,
  'ampliada': 0.85,
}[normalized.cobertura.franquiaPerfil] ?? 1.00;

// Adicionais (RCF materiais/corporais e APP somam)
const adicRcf = (normalized.cobertura.rcfMateriais + normalized.cobertura.rcfCorporais) * 0.0012;
const adicApp = normalized.cobertura.appCapital * 0.0020;

function premioAnual(multMarca) {
  const base = fipe * taxaBase * multSexo * multExperiencia *
               multUsoComercial * multGaragem * multCep *
               multCobertura * multFranquia;
  return (base + adicRcf + adicApp) * multMarca;
}

const operadoras = [
  {
    codigo: 'PRT',
    nome: 'Porto Seguro',
    registroSusep: '0292-0',
    produto: 'Auto Carro Fácil',
    multMarca: 1.00,
    franquiaReduzida: 3200,
    franquiaNormal: 4500,
    franquiaAmpliada: 6500
  },
  {
    codigo: 'BRD',
    nome: 'Bradesco Auto',
    registroSusep: '0153-1',
    produto: 'Bradesco Auto Primeiro Protegido',
    multMarca: 1.04,
    franquiaReduzida: 3000,
    franquiaNormal: 4300,
    franquiaAmpliada: 6200
  },
  {
    codigo: 'SUL',
    nome: 'SulAmérica Auto',
    registroSusep: '0477-8',
    produto: 'SulAmérica Auto Ativo',
    multMarca: 0.97,
    franquiaReduzida: 3400,
    franquiaNormal: 4700,
    franquiaAmpliada: 6700
  }
];

const planos = operadoras
  .map(op => {
    const ruido = 1 + randRange(-0.03, 0.03);
    const anual = Math.round(premioAnual(op.multMarca) * ruido * 100) / 100;
    const mensal = Math.round(anual / 12 * 100) / 100;
    const franquia = {
      'reduzida': op.franquiaReduzida,
      'normal': op.franquiaNormal,
      'ampliada': op.franquiaAmpliada
    }[normalized.cobertura.franquiaPerfil] ?? op.franquiaNormal;

    const coberturasList = [{
      tipo: normalized.cobertura.tipo,
      valorFipeSimulado: fipe,
      franquia,
    }];
    if (normalized.cobertura.rcfMateriais > 0) coberturasList.push({
      tipo: 'rcf_materiais',
      capital: normalized.cobertura.rcfMateriais
    });
    if (normalized.cobertura.rcfCorporais > 0) coberturasList.push({
      tipo: 'rcf_corporais',
      capital: normalized.cobertura.rcfCorporais
    });
    if (normalized.cobertura.appCapital > 0) coberturasList.push({
      tipo: 'app_acidentes_pessoais',
      capital: normalized.cobertura.appCapital
    });

    return {
      planId: `${op.codigo}-${hashHex.slice(0, 6)}`,
      operadora: {
        codigo: op.codigo,
        nome: op.nome,
        registroSusep: op.registroSusep
      },
      produto: {
        nome: `${op.nome} ${op.produto}`,
        vigencia: '12 meses renovável'
      },
      premio: {
        mensal,
        anual,
        iof: 0.0738 * anual,
        moeda: 'BRL'
      },
      coberturas: coberturasList,
      assistencia24h: ['guincho 300km', 'chaveiro', 'troca de pneu'],
      exclusoesImportantes: [
        'Condutor não declarado com menos de 26 anos',
        'Uso comercial não declarado',
        'Direção sob efeito de álcool/substâncias'
      ]
    };
  })
  .sort((a, b) => a.premio.mensal - b.premio.mensal);

function formatCpf(digits) {
  if (!digits || digits.length !== 11) return null;
  return digits.replace(/(\d{3})(\d{3})(\d{3})(\d{2})/, '$1.$2.$3-$4');
}

function formatPlaca(raw) {
  if (!raw || raw.length !== 7) return raw;
  return raw.slice(0, 3) + '-' + raw.slice(3);
}

const now = DateTime.now();

return [{
  json: {
    data: {
      consentId,
      quoteStatus: 'ACKNOWLEDGED',
      requestDateTime: now.toISO(),
      validadeDias: 30,
      veiculo: {
        ...normalized.veiculo,
        placa: formatPlaca(normalized.veiculo.placa),
        valorFipeSimulado: fipe
      },
      condutor: {
        ...normalized.condutor,
        cpf: formatCpf(normalized.condutor.cpf),
        idade,
        anosCnh
      },
      localizacao: normalized.localizacao,
      cobertura: normalized.cobertura,
      planos
    },
    meta: {
      totalPlanos: planos.length,
      apiVersion: 'opin-style-auto-v1',
      deterministicHash: hashHex.slice(0, 16),
      requestDateTime: now.toISO(),
      disclaimer: 'Resposta simulada. Auto é regulado pela SUSEP; as taxas e preços aqui são didáticos. Em produção, usar API da seguradora parceira.'
    }
  }
}];

/**
 * Passo 1 (Auto) — Valida consentId recalculando o hash do originalQuoteRequest.
 *
 * Mock stateless: cliente reenvia `originalQuoteRequest` (mesmo payload do POST
 * /quote-auto/request) junto com `selectedPlan`, `paymentConfirmation` e
 * `acceptance: true`. A normalização tem que ser idêntica à do request.
 */

const incoming = $input.first().json;
const body = incoming.body ?? incoming;
const headers = incoming.headers ?? {};
const payload = body.data ?? body;

