  return [{ json: { __error: 'MISSING_SELECTED_PLAN', detail: 'payload.selectedPlan deve conter planId ou operadora.codigo.' } }];
}
if (acceptance !== true) {
  return [{ json: { __error: 'ACCEPTANCE_REQUIRED', detail: 'payload.acceptance deve ser true para emitir a apólice.' } }];
}
if (!paymentConfirmation?.transactionId) {
  return [{ json: { __error: 'PAYMENT_REQUIRED', detail: 'payload.paymentConfirmation.transactionId é obrigatório.' } }];
}

function onlyDigits(s) { return String(s ?? '').replace(/\D/g, ''); }
function normalizeDate(s) { return s ? String(s).slice(0, 10) : null; }
function toNum(v) { const n = Number(v); return Number.isFinite(n) ? n : 0; }

const veiculo = originalQuoteRequest.veiculo ?? {};
const condutor = originalQuoteRequest.condutor ?? {};
