  veiculo: {
    placa: String(veiculo.placa ?? '').toUpperCase().replace(/[^A-Z0-9]/g, ''),
    chassi: String(veiculo.chassi ?? '').toUpperCase().replace(/[^A-Z0-9]/g, ''),
    marca: String(veiculo.marca ?? '').toLowerCase(),
    modelo: String(veiculo.modelo ?? '').toLowerCase(),
    anoModelo: toNum(veiculo.anoModelo),
    combustivel: String(veiculo.combustivel ?? 'flex').toLowerCase(),
    categoria: String(veiculo.categoria ?? 'passeio').toLowerCase(),
  },
  condutor: {
    cpf: onlyDigits(condutor.cpf),
    dataNascimento: normalizeDate(condutor.dataNascimento),
    sexo: sexoNorm,
    cnhDesde: normalizeDate(condutor.cnhDesde),
    estadoCivil: String(condutor.estadoCivil ?? 'solteiro').toLowerCase(),
    usoPrincipal: String(condutor.usoPrincipal ?? 'particular').toLowerCase(),
  },
  localizacao: {
    cep: onlyDigits(localizacao.cep),
    cidade: String(localizacao.cidade ?? '').toLowerCase(),
    usoComercial: Boolean(localizacao.usoComercial ?? false),
    garagem: Boolean(localizacao.garagem ?? true),
  },
  cobertura: {
    tipo: tipoCoberturaNorm,
    franquiaPerfil: String(cobertura.franquiaPerfil ?? 'normal').toLowerCase(),
    appCapital: toNum(cobertura.appCapital),
    rcfMateriais: toNum(cobertura.rcfMateriais),
    rcfCorporais: toNum(cobertura.rcfCorporais),
