  h1 = Math.imul(h3 ^ (h1 >>> 18), 597399067);
  h2 = Math.imul(h4 ^ (h2 >>> 22), 2869860233);
  h3 = Math.imul(h1 ^ (h3 >>> 17), 951274213);
  h4 = Math.imul(h2 ^ (h4 >>> 19), 2716044179);
  h1 ^= (h2 ^ h3 ^ h4); h2 ^= h1; h3 ^= h1; h4 ^= h1;
  return [h1 >>> 0, h2 >>> 0, h3 >>> 0, h4 >>> 0];
}

const hashParts = cyrb128(JSON.stringify(normalized));
const hashHex = hashParts.map(n => n.toString(16).padStart(8, '0')).join('');
const expectedConsentId = [
  'urn:opin-mock:auto:consent:',
  hashHex.slice(0, 8), '-',
  hashHex.slice(8, 12), '-',
  hashHex.slice(12, 16), '-',
  hashHex.slice(16, 20), '-',
  hashHex.slice(20, 32)
].join('');

const consentMatches = expectedConsentId === consentIdFromPath;

return [{
  json: {
    consentMatches,
    consentIdFromPath,
    expectedConsentId,
    normalized,
    hashHex,
    seed: hashParts[0],
    selectedPlan,
    paymentConfirmation,
    __error: null
  }
}];

/**
 * Passo 2 (Auto, sucesso) — Emite apólice de AUTO determinística.
 *
 * Recomputa planos com o MESMO PRNG do fluxo de cotação para que o prêmio
 * emitido bata com o mostrado na cotação. policyNumber derivado do hash +
 * operadora. Vigência padrão: 12 meses renováveis.
 */

const { normalized, hashHex, seed, selectedPlan, paymentConfirmation, consentIdFromPath } = $input.first().json;

let s = seed;
const rand = () => {
  s = (s + 0x6D2B79F5) | 0;
  let t = s;
  t = Math.imul(t ^ (t >>> 15), t | 1);
  t ^= t + Math.imul(t ^ (t >>> 7), t | 61);
  return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
};
const randRange = (min, max) => min + rand() * (max - min);

function idadeAnos(dn) {
  if (!dn) return 35;
  const d = DateTime.fromISO(dn);
  if (!d.isValid) return 35;
  return Math.max(0, Math.floor(DateTime.now().diff(d, 'years').years));
}
function anosHabilitado(dt) {
  if (!dt) return 5;
  const d = DateTime.fromISO(dt);
  if (!d.isValid) return 5;
  return Math.max(0, Math.floor(DateTime.now().diff(d, 'years').years));
}
function valorFipeSimulado(anoModelo, categoria) {
  const anosUso = Math.max(0, DateTime.now().year - anoModelo);
  const depreciacao = Math.max(0.25, 1 - anosUso * 0.09);
  const baseCategorias = {
    'passeio': 80000, 'hatch': 65000, 'sedan': 95000,
    'suv': 140000, 'pickup': 180000, 'utilitario': 110000,
  };
  const base = baseCategorias[categoria] ?? 85000;
  return Math.round(base * depreciacao);
}
function riscoCep(cep) {
  const p = Number(String(cep).slice(0, 2));
  if (!Number.isFinite(p)) return 1.0;
  if ([1, 2, 3, 4, 5, 20, 21, 22, 23, 24, 50, 51, 52, 53, 54, 55, 57, 58].includes(p)) return 1.20;
  if ([13, 40, 41, 60, 69, 70, 80, 90].includes(p)) return 1.05;
  return 0.95;
}

const idade = idadeAnos(normalized.condutor.dataNascimento);
const anosCnh = anosHabilitado(normalized.condutor.cnhDesde);
const sexo = normalized.condutor.sexo;
const anoModelo = normalized.veiculo.anoModelo;
const fipe = valorFipeSimulado(anoModelo, normalized.veiculo.categoria);

function taxaPorIdade(i) {
  if (i < 25) return 0.080;
  if (i < 30) return 0.055;
  if (i < 40) return 0.038;
  if (i < 55) return 0.030;
  if (i < 65) return 0.034;
  return 0.045;
}

const taxaBase = taxaPorIdade(idade);
const multSexo = sexo === 'f' ? 0.90 : 1.00;
const multExperiencia = anosCnh < 2 ? 1.40 : anosCnh < 5 ? 1.15 : anosCnh < 15 ? 1.00 : 0.93;
const multUsoComercial = normalized.localizacao.usoComercial ? 1.25 : 1.00;
const multGaragem = normalized.localizacao.garagem ? 0.93 : 1.08;
const multCep = riscoCep(normalized.localizacao.cep);

const multCobertura = {
  'compreensiva': 1.00, 'rcf': 0.45, 'app': 0.20, 'basica': 0.30,
}[normalized.cobertura.tipo] ?? 1.00;

const multFranquia = {
  'reduzida': 1.18, 'normal': 1.00, 'ampliada': 0.85,
}[normalized.cobertura.franquiaPerfil] ?? 1.00;

const adicRcf = (normalized.cobertura.rcfMateriais + normalized.cobertura.rcfCorporais) * 0.0012;
const adicApp = normalized.cobertura.appCapital * 0.0020;

function premioAnual(multMarca) {
  const base = fipe * taxaBase * multSexo * multExperiencia *
               multUsoComercial * multGaragem * multCep *
               multCobertura * multFranquia;
  return (base + adicRcf + adicApp) * multMarca;
}

const operadoras = [
  { codigo: 'PRT', nome: 'Porto Seguro',    registroSusep: '0292-0', produto: 'Auto Carro Fácil',                   multMarca: 1.00,
    franquiaReduzida: 3200, franquiaNormal: 4500, franquiaAmpliada: 6500 },
  { codigo: 'BRD', nome: 'Bradesco Auto',   registroSusep: '0153-1', produto: 'Bradesco Auto Primeiro Protegido',   multMarca: 1.04,
    franquiaReduzida: 3000, franquiaNormal: 4300, franquiaAmpliada: 6200 },
  { codigo: 'SUL', nome: 'SulAmérica Auto', registroSusep: '0477-8', produto: 'SulAmérica Auto Ativo',              multMarca: 0.97,
    franquiaReduzida: 3400, franquiaNormal: 4700, franquiaAmpliada: 6700 }
];

// Recompute planos in SAME order as quote flow so PRNG aligns
const planosRecomputados = operadoras.map(op => {
  const ruido = 1 + randRange(-0.03, 0.03);
  const anual = Math.round(premioAnual(op.multMarca) * ruido * 100) / 100;
  const mensal = Math.round(anual / 12 * 100) / 100;
  return {
    planId: `${op.codigo}-${hashHex.slice(0, 6)}`,
    operadora: op,
    premio: { mensal, anual, iof: 0.0738 * anual, moeda: 'BRL' }
  };
});

const planoEscolhido = planosRecomputados.find(p =>
  (selectedPlan.planId && p.planId === selectedPlan.planId) ||
  (selectedPlan.operadora?.codigo && p.operadora.codigo === selectedPlan.operadora.codigo)
);

if (!planoEscolhido) {
  throw new Error(`Plano selecionado não encontrado na cotação original: ${JSON.stringify(selectedPlan)}`);
}

const franquia = {
  'reduzida': planoEscolhido.operadora.franquiaReduzida,
  'normal': planoEscolhido.operadora.franquiaNormal,
  'ampliada': planoEscolhido.operadora.franquiaAmpliada
}[normalized.cobertura.franquiaPerfil] ?? planoEscolhido.operadora.franquiaNormal;

const policyNumber = `AT-${planoEscolhido.operadora.codigo}-${hashHex.slice(0, 8).toUpperCase()}`;
const policyId = `urn:opin-mock:auto:policy:${hashHex.slice(0, 8)}-${hashHex.slice(8, 12)}-${hashHex.slice(12, 16)}-${hashHex.slice(16, 20)}-${hashHex.slice(20, 32)}`;

const now = DateTime.now();
const startDate = now;
const endDate = now.plus({ years: 1 });

const coberturasEmitidas = [{
  tipo: normalized.cobertura.tipo,
  valorFipeSimulado: fipe,
  franquia,
}];
if (normalized.cobertura.rcfMateriais > 0) coberturasEmitidas.push({ tipo: 'rcf_materiais', capital: normalized.cobertura.rcfMateriais });
if (normalized.cobertura.rcfCorporais > 0) coberturasEmitidas.push({ tipo: 'rcf_corporais', capital: normalized.cobertura.rcfCorporais });
if (normalized.cobertura.appCapital > 0)   coberturasEmitidas.push({ tipo: 'app_acidentes_pessoais', capital: normalized.cobertura.appCapital });

function formatCpf(digits) {
  if (!digits || digits.length !== 11) return null;
  return digits.replace(/(\d{3})(\d{3})(\d{3})(\d{2})/, '$1.$2.$3-$4');
}
function formatPlaca(raw) {
  if (!raw || raw.length !== 7) return raw;
  return raw.slice(0, 3) + '-' + raw.slice(3);
}

return [{
  json: {
    data: {
      policyId,
      policyNumber,
      consentId: consentIdFromPath,
      issueDateTime: now.toISO(),
      startDate: startDate.toISODate(),
      endDate: endDate.toISODate(),
      status: 'ACTIVE',
      veiculo: {
        ...normalized.veiculo,
        placa: formatPlaca(normalized.veiculo.placa),
        valorFipeSimulado: fipe
      },
      condutor: {
        ...normalized.condutor,
        cpf: formatCpf(normalized.condutor.cpf),
        idade,
        anosCnh
      },
      localizacao: normalized.localizacao,
      coberturas: coberturasEmitidas,
      selectedPlan: {
        planId: planoEscolhido.planId,
        operadora: {
          codigo: planoEscolhido.operadora.codigo,
          nome: planoEscolhido.operadora.nome,
          registroSusep: planoEscolhido.operadora.registroSusep
        },
        produto: {
          nome: `${planoEscolhido.operadora.nome} ${planoEscolhido.operadora.produto}`,
          vigencia: '12 meses renovável'
        }
      },
      premium: {
        mensal: planoEscolhido.premio.mensal,
        anual: planoEscolhido.premio.anual,
        iof: planoEscolhido.premio.iof,
        moeda: 'BRL'
      },
      payment: {
        method: paymentConfirmation.method ?? null,
        transactionId: paymentConfirmation.transactionId
      },
      documents: {
        policyPdfUrl: `https://mock.opin-style/auto/policies/${hashHex.slice(0, 32)}.pdf`,
        resumoContratualUrl: `https://mock.opin-style/auto/docs/resumo-${hashHex.slice(0, 16)}.pdf`
      }
    },
    meta: {
      apiVersion: 'opin-style-auto-v1',
      requestDateTime: now.toISO(),
      disclaimer: 'Apólice simulada. Auto é regulado pela SUSEP, não pelo OPIN.'
    }
  }
}];

/**
 * Passo 2 (erro) — Monta ResponseError OPIN-style.
 */

const input = $input.first().json;
const now = DateTime.now();

const errorMap = {
  MISSING_CONSENT_ID:      { title: 'consentId ausente', httpCode: 400 },
  MISSING_ORIGINAL_REQUEST: { title: 'originalQuoteRequest obrigatório', httpCode: 400 },
  MISSING_SELECTED_PLAN:   { title: 'selectedPlan obrigatório', httpCode: 400 },
  ACCEPTANCE_REQUIRED:     { title: 'acceptance precisa ser true', httpCode: 400 },
  PAYMENT_REQUIRED:        { title: 'paymentConfirmation obrigatório', httpCode: 400 },
  CONSENT_MISMATCH:        { title: 'consentId não confere com originalQuoteRequest', httpCode: 422 }
};

const code = input.__error ?? 'CONSENT_MISMATCH';
const detail = input.detail ?? (
  code === 'CONSENT_MISMATCH'
    ? `O hash recomputado do originalQuoteRequest não bate com o consentId informado (${input.consentIdFromPath}).`
    : 'Erro de validação.'
);
const meta = errorMap[code] ?? errorMap.CONSENT_MISMATCH;

return [{
  json: {
    errors: [{ code, title: meta.title, detail }],
    meta: {
      apiVersion: 'opin-style-life-v1',
      requestDateTime: now.toISO(),
      httpCode: meta.httpCode
    }
  }
}];
